const aiOutput = $input.first().json.output || $input.first().json.text || '';
const client = $('Validar y Formatear').first().json;
let diagnosis;
try {
  const match = aiOutput.match(/\{[\s\S]*\}/);
  diagnosis = match ? JSON.parse(match[0]) : { diagnosticoGratuito: { resumen: aiOutput } };
} catch(e) {
  diagnosis = { diagnosticoGratuito: { resumen: aiOutput } };
}

const urgencyColor = client.cobroCoactivo === 'Sí' ? '#d32f2f' : '#1a3a5c';
const urgencyMessage = client.cobroCoactivo === 'Sí' ? 
  '⚠️ URGENTE: Su caso tiene Cobro Coactivo activo. Es importante actuar pronto.' : 
  'Su caso ha sido registrado y ha recibido diagnóstico gratuito.';

const emailHtml = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: ${urgencyColor}; padding: 20px; text-align: center;">
    <h1 style="color: white; margin: 0;">Multas de Tránsito</h1>
    <p style="color: #ffcccc; margin: 5px 0;">Diagnóstico Gratuito — Ekinoxis</p>
  </div>
  <div style="padding: 30px; background: #f9f9f9;">
    <p>Estimado/a <strong>${client.nombres}</strong>,</p>
    <p>${urgencyMessage}</p>
    <div style="background: white; border-left: 4px solid ${urgencyColor}; padding: 15px; margin: 20px 0;">
      <h3 style="color: ${urgencyColor}; margin-top: 0;">📋 Caso #${client.caseId} — Diagnóstico Gratuito</h3>
      <p>${diagnosis.diagnosticoGratuito?.resumen || 'Su caso está siendo analizado.'}</p>
      ${diagnosis.diagnosticoGratuito?.advertenciaCobroCoactivo ? `<p><strong>⚠️ Cobro Coactivo:</strong> ${diagnosis.diagnosticoGratuito.advertenciaCobroCoactivo}</p>` : ''}
      <p><strong>Posibilidad de prescripción:</strong> ${diagnosis.diagnosticoGratuito?.posibilidadPrescripcion || 'Por determinar con documentos'}</p>
    </div>
    <div style="background: #fff3e0; padding: 15px; border-radius: 5px; margin: 15px 0;">
      <h4>📄 Documentos que necesitará:</h4>
      <ul>${(diagnosis.diagnosticoGratuito?.documentosNecesarios || []).map(d => `<li>${d}</li>`).join('')}</ul>
    </div>
    <p><strong>Ahorro estimado:</strong> ${diagnosis.estimadoAhorro || 'Se calculará con los documentos'}</p>
    <div style="background: #e8f5e9; padding: 15px; border-radius: 5px;">
      <h4 style="color: #2e7d32;">Cómo continuar — Paso 2:</h4>
      <p>${diagnosis.siguientesPasos || 'Contacte nuestro equipo para iniciar el proceso formal.'}</p>
      <p><strong>Costo:</strong> Solo el 50% del valor que ahorre (paga solo si hay ahorro)</p>
    </div>
  </div>
  <div style="background: ${urgencyColor}; padding: 15px; text-align: center;">
    <p style="color: white; margin: 0; font-size: 12px;">© Ekinoxis | Para continuar con su caso, responda este correo</p>
  </div>
</div>`;

return [{json: { ...client, diagnosis, emailHtml }}];

